import{_ as e,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Household Measurement Overview","description":"","frontmatter":{"title":"Household Measurement Overview","slug":"household-measurement"},"headers":[],"relativePath":"marketer-hub/household-measurement.md","filePath":"marketer-hub/household-measurement.md"}'),d={name:"marketer-hub/household-measurement.md"};function s(n,t,i,h,l,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>.png)Users are spending more time with their connected TVs (CTVs) than ever before, making it an increasingly important part of any cross-platform growth strategy.</p><p>CTV refers to the <strong>devices</strong> themselves that enable streaming video over the internet, e.g. smart TVs, streaming devices, and gaming consoles.</p><p>If you want to tap into this growth, having an accurate attribution provider is essential to your ads strategy.</p><p>Branch&#39;s Household Measurement feature offers comprehensive attribution support for household devices, allowing you to measure down-funnel events. This gives you a holistic view of your users&#39; actions and <strong>the data you need to optimize your campaigns and your TV ad budgets</strong>.</p><p>Read more about Household Measurement, the problem it&#39;s solving, and the benefits of the feature below.</p><h2 id="what-is-household-measurement" tabindex="-1">What is Household Measurement? <a class="header-anchor" href="#what-is-household-measurement" aria-label="Permalink to &quot;What is Household Measurement?&quot;">​</a></h2><p>.png)Branch&#39;s Household Measurement feature is able to track downstream conversions across multiple household devices, such as mobile phones, desktops, laptops, and tablets.</p><p>Household Measurement attributes TV ad engagements to downstream conversions on other devices, which gives you more precise performance tracking and enables you to justify your TV ad spend.</p><p>Importantly, Branch integrates with major CTV platforms and in doing so <strong>covers over 95% of streaming worldwide</strong>.</p><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><p>Let&#39;s take a quick tour of some of the key benefits of Household Measurement.</p><h4 id="easily-measure-roas" tabindex="-1">Easily Measure ROAS <a class="header-anchor" href="#easily-measure-roas" aria-label="Permalink to &quot;Easily Measure ROAS&quot;">​</a></h4><p>Measure ad performance across various devices to accurately understand your return on ad spend.</p><h4 id="analyze-cross-device-performance" tabindex="-1">Analyze Cross-Device Performance <a class="header-anchor" href="#analyze-cross-device-performance" aria-label="Permalink to &quot;Analyze Cross-Device Performance&quot;">​</a></h4><p>Analyze and report on conversions across mobile, web, desktop, and living room devices - all with one solution.</p><h4 id="de-duplicate-marketing-data" tabindex="-1">De-duplicate Marketing Data <a class="header-anchor" href="#de-duplicate-marketing-data" aria-label="Permalink to &quot;De-duplicate Marketing Data&quot;">​</a></h4><p>Ensure every customer touchpoint is only counted once, which provides an accurate view of campaign effectiveness.</p><h4 id="improve-retargeting-efforts" tabindex="-1">Improve Retargeting Efforts <a class="header-anchor" href="#improve-retargeting-efforts" aria-label="Permalink to &quot;Improve Retargeting Efforts&quot;">​</a></h4><p>Improve retargeting efforts by sharing conversions with ad partners that they can&#39;t track on their own.</p><h2 id="attribution-flows" tabindex="-1">Attribution Flows <a class="header-anchor" href="#attribution-flows" aria-label="Permalink to &quot;Attribution Flows&quot;">​</a></h2><p>Household Measurement supports three attribution flows. Learn about each below.</p><h4 id="tv-to-tv" tabindex="-1">TV to TV <a class="header-anchor" href="#tv-to-tv" aria-label="Permalink to &quot;TV to TV&quot;">​</a></h4><p>View-through and click-through attribution of TV ad engagements. Put differently, this measures <strong>TV ad engagements to TV conversions</strong>.</p><p>.png)</p><h4 id="tv-to-web-mobile" tabindex="-1">TV to Web/Mobile <a class="header-anchor" href="#tv-to-web-mobile" aria-label="Permalink to &quot;TV to Web/Mobile&quot;">​</a></h4><p>View-through attribution of TV ad impressions that lead to a conversion on web or mobile. Here we are measuring <strong>TV ad engagements that lead to non-TV (web/mobile) ad engagements</strong>.</p><p>.png)</p><h4 id="web-mobile-to-tv" tabindex="-1">Web/Mobile to TV <a class="header-anchor" href="#web-mobile-to-tv" aria-label="Permalink to &quot;Web/Mobile to TV&quot;">​</a></h4><p>View-through of web or mobile ad impressions that lead to a TV conversion. This measures <strong>non-TV (web/mobile) ad engagements to TV ad engagements</strong>.</p><p>.png)</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><p>Let&#39;s dive into some examples of top use cases for Household Measurement, so you can start to see it in action.</p><h4 id="cross-device-linking" tabindex="-1">Cross-Device Linking <a class="header-anchor" href="#cross-device-linking" aria-label="Permalink to &quot;Cross-Device Linking&quot;">​</a></h4><p>Power sophisticated user experiences by leveraging Branch QR Codes to drive mobile app engagement from CTV, or to simplify the login process.</p><h4 id="display-and-video-ads" tabindex="-1">Display and Video Ads <a class="header-anchor" href="#display-and-video-ads" aria-label="Permalink to &quot;Display and Video Ads&quot;">​</a></h4><p>Understand the influence your CTV ads have on downstream conversion events across mobile, web, and desktop devices.</p><h4 id="engagement-ads" tabindex="-1">Engagement Ads <a class="header-anchor" href="#engagement-ads" aria-label="Permalink to &quot;Engagement Ads&quot;">​</a></h4><p>Track which CTV ad impressions and clicks led to subsequent TV conversions.</p><h4 id="mobile-ads-to-ctv-streaming" tabindex="-1">Mobile Ads to CTV Streaming <a class="header-anchor" href="#mobile-ads-to-ctv-streaming" aria-label="Permalink to &quot;Mobile Ads to CTV Streaming&quot;">​</a></h4><p>Measure the effectiveness of your mobile ads by tracking how they drive user engagement on CTV streaming platforms.</p><h4 id="pre-install-tracking" tabindex="-1">Pre-Install Tracking <a class="header-anchor" href="#pre-install-tracking" aria-label="Permalink to &quot;Pre-Install Tracking&quot;">​</a></h4><p>Measure app installs from apps packaged with your partner platforms.</p><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">​</a></h2><p>The table below details which Household Measurement features are supported on which CTV platforms.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Details</th><th>Roku</th><th>Amazon Fire TV</th><th>Apple TV</th><th>Android TV</th><th>Samsung TV</th><th>Xbox</th><th>LG</th><th>Panasonic</th></tr></thead><tbody><tr><td>Engagement and Install Ads</td><td>Understand which ad impressions and clicks drove installs.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Pre-Install Tracking</td><td>Measure app installs from apps packaged with your partner platforms.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Session Counts</td><td>Measure daily installs, opens, and session length.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Deep Linking</td><td>Route users to in-app content directly from the ad.</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>App-to-App Activity</td><td>Measure user journeys to and from your various OTT apps.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Conversion Events</td><td>Attribute conversions back to the last ad seen or Branch Link clicked.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Partner Events</td><td>Forward activity from partners directly to Branch.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>GDPR Compliance</td><td>Ability to comply with GDPR requirements.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Cross-Device Attribution</td><td>Capture mobile app conversions and events triggered by CTV ads on the same IP address.</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><p>You can implement Household Measurement either through our <strong>SDK or a Server-to-Server (S2S)</strong> integration. Each of these has their own pros and cons, but Branch recommends an SDK integration when possible.</p><p>Work with your development team to determine which integration type is right for you using the table below.</p><table tabindex="0"><thead><tr><th>Capability</th><th>Details</th><th>Integration Recommendation</th></tr></thead><tbody><tr><td>Platform Specificities &amp; Flexibility</td><td>Certain CTV platforms only support specific ways of implementation.</td><td><strong>S2S</strong> might be required because some platforms do not have a Branch SDK to integrate. S2S integration will work for all platforms.</td></tr><tr><td>Ease of Implementation</td><td>Utilize an implementation for session management, installs, and capturing device identifiers.</td><td><strong>SDK</strong> is preferred because Branch will handle the session automatically, while S2S will require additional work to capture the necessary parameters in order to make the requests.</td></tr><tr><td>Long-Term Upkeep</td><td>With updates to platforms, keeping up with changes is necessary to comply with privacy or to add new features.</td><td><strong>SDK</strong> is preferred because when there is a change to the platform, you would only need to update the SDK while you may have to change core logic in an S2S integration.</td></tr></tbody></table><p>Once you&#39;ve decided on an integration type, see the guides below to get started.</p><table tabindex="0"><thead><tr><th>Integration Type</th><th>Supported Platforms</th></tr></thead><tbody><tr><td>SDK</td><td>- <a href="./roku.html">Roku</a> - <a href="./android-sdk-overview.html">Amazon Fire TV</a> - <a href="./android-sdk-overview.html">Android TV</a> - <a href="./ios-sdk-overview.html">Apple TV</a> - Samsung TV, Xbox, LG, Panasonic via <a href="./connected-sdk.html">Connected SDK</a></td></tr><tr><td><a href="./desktop-over-the-top-ott-attribution.html">S2S</a></td><td>All</td></tr></tbody></table>',52)])])}const m=e(d,[["render",s]]);export{c as __pageData,m as default};
